// And groups predicates with the AND operator between them.
func And(predicates ...predicate.Gasto) predicate.Gasto {
	return predicate.Gasto(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.Gasto) predicate.Gasto {
	return predicate.Gasto(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.Gasto) predicate.Gasto {
	return predicate.Gasto(sql.NotPredicates(p))
}
